var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 건틀렛 본선 8강 토너먼트.\\n시작 세 시간 전.","JPN":"シャレードガントレット本戦準々決勝トーナメント。\\n開始3時間前","ENG":"[[","TWN":"查雷德聖鎧決賽八強淘汰賽。\\n開始前三小時。","SCN":"查雷德圣铠决赛八强淘汰赛。\\n开始前三小时。","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"저… 다시 한번 확인하겠습니다.","JPN":"ええと……もう一度確認します。","ENG":"Um... I'll confirm just one more time.","TWN":"我……再確認一次。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"카나리아의 추가 엔트리 멤버의 경우, 선수 등록을 위해 두 시간 전까지는 경기장에 도착하셔야 합니다.","JPN":"カナリアの追加エントリーメンバーは、選手登録のために、2時間前には競技場に到着していただく必要があります。","ENG":"Any additional entry for Canary Squad must arrive at the stadium at least two hours before the match.","TWN":"金絲雀的額外參賽成員需要在兩小時前到達賽場進行選手登記。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"물론, 시간 외 경기장 난입은 불가능하고요.","JPN":"もちろん、時間外の競技場への乱入は禁止です。","ENG":"Of course, entering the arena outside that window is prohibited.","TWN":"當然，規定時間外無法進入競技場。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정 말게. 그 둘이라면 늦지 않을 테니.","JPN":"心配いらない。彼らなら間に合うはずだ。","ENG":"Don't worry. Those two won't be late.","TWN":"別擔心。那兩個人不會遲到的。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"펠리세트와 스키너 양도 라이카 양의 병문안에 갔을 뿐이니, 곧 도착할 걸세.","JPN":"フェリセットとスキナー君も、ライカ君の見舞いに行っただけだから、すぐ着くはずさ。","ENG":"Félicette and Skinner just went to visit Laika in the hospital. They should be back soon.","TWN":"費莉塞特和史金納只是去探望萊卡，很快就會到的。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"예. 그럼 팀 엔트리는 건네주신 것과 동일하게 진행하겠습니다.","JPN":"はい。では、チームのエントリーはお渡しいただいた通り進めさせていただきます。","ENG":"Understood. Then I'll proceed with the team entry as previously submitted.","TWN":"好的，那麼團隊名單將按照你提供的進行。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"규칙을 어겨 발생하는 페널티는 온전히 팀의 몫이니, 이 점 명심해주시길.","JPN":"ルールを破って発生するペナルティについては、チームの責任となりますから、どうかご注意を。","ENG":"Please keep in mind that any penalties from rule violations fall entirely on the team.","TWN":"違反規則所產生的懲罰將完全由團隊承擔，請牢記這一點。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저기, 사장님.","JPN":"ねえ、社長。","ENG":"Hey, Boss.","TWN":"那個，老闆。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미나 양도 그 둘이 걱정되나?","JPN":"ミナ君も二人が心配なのか？","ENG":"Are you worried about those two too, Mina?","TWN":"米娜也擔心那兩個人嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"교체 선수가 늦을 거라는 걱정은 안 해. 그냥, 그 둘을 선택한 이유가 있나 싶어서.","JPN":"交代選手が遅れるとは思わないよ。ただ、その二人を選んだ理由があるのかなと思って。","ENG":"Not worried about them being late. I was just curious why you picked them.","TWN":"不是擔心替補選手會遲到。我只是好奇，為什麼選擇了那兩個人。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"팀으로 움직이는 거라면 회사 사람들이 낫지 않았나 싶은데.","JPN":"チームで動くのなら、会社の人のほうがよかったんじゃないの？","ENG":"If it's about teamwork, wouldn't using our company employees be better?","TWN":"如果是團隊行動的話，公司的人不是更好嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"부사장은 자네가 설득하고?","JPN":"副社長は君が説得するのかい？","ENG":"And you'd be the one to convince the Vice President?","TWN":"你跟副總說？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"걱정 말게. 여차하면 미나 양이 뛰면 그만 아닌가?","JPN":"心配は無用だ。いざとなればミナ君が参加すればいい。","ENG":"Besides, in the worst-case scenario, you can always jump in.","TWN":"不用擔心。實在不行的話，讓米娜來就行了吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"농담하는 걸 보면 믿는 구석이 있는 모양이네.","JPN":"そんな冗談が言えるってことは、なにか確信があるんだね。","ENG":"You must be pretty confident to joke like that.","TWN":"看你開玩笑的樣子，看來是有留兩手啊。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론이지. 나름 전력차를 메울 수 있는 요소를 갖춘 친구들로 선별했다네.","JPN":"もちろんだ。戦力差を埋められる要素を考慮した人選だ。","ENG":"Of course. I chose them because they have what it takes to close the power gap.","TWN":"當然。我挑選了一些能夠彌補戰力差距的朋友。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무엇보다 우리에겐 노엘 양이 있지 않나?","JPN":"何より、こちらにはノエル君がいるじゃないか。","ENG":"And above all, we have Noelle on our side.","TWN":"最重要的是，我們有洛艾兒，不是嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네-엡! 이 노엘. 적 장수의 목을 단숨에 베어오겠습니다!","JPN":"はーいっ！　このノエルが敵将の首を刈り取ってみせます！","ENG":"Yup! I, Noelle, shall bring back the enemy commander's head in one stroke!","TWN":"是-嗯！我是洛艾兒。我會一口氣砍下敵將的頭顱！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좋은 기세일세. 코핀 컴퍼니 헤드 스쿼드 멤버의 힘을 저들에게 보여주세나.","JPN":"いい勢いだ。コフィンカンパニー主要メンバーの力を彼らに見せつけてくれ。","ENG":"That's the spirit. Show them the strength of a Head Squad member from Coffin Company.","TWN":"氣勢不錯。讓他們見識一下科芬公司主力小隊成員的實力吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펜릴 소대 스타일로 말이죠?","JPN":"フェンリル小隊のスタイルでですね？","ENG":"You got it, Fenrir Squad style, right?","TWN":"芬里爾小隊風格的說法嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"소대장 스타일로 부탁하네.","JPN":"小隊長スタイルで頼む。","ENG":"Preferably, Division Commander style.","TWN":"請以小隊長的風格來做。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"미나 양처럼 싸우는 게 좋겠군.","JPN":"ミナ君スタイルがいいな。","ENG":"Fighting like Mina would be best.","TWN":"像米娜那樣戰鬥會比較好。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"맡겨만 주세요, 사장님! 적을 <color=#ff3636>[검열됨]</color>해서 <color=#ff3636>[검열됨]</color>하겠습니다!!","JPN":"任せてください、社長！　敵を<color=#ff3636>[検閲済]</color>して<color=#ff3636>[検閲済]</color>してやります！！","ENG":"Leave it to me, Boss! I'll <color=#ff3636>[BLEEP]</color> the enemy and then <color=#ff3636>[BLEEP]</color> them!","TWN":"交給我們吧，老闆！我們會<color=#ff3636>[已審查]</color>敵人並<color=#ff3636>[已審查]</color>他們！！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……아니, 그렇게까지 안 하거든.","JPN":"……いや、そこまではやってないから。","ENG":"...Okay, I don't go that far.","TWN":"……不，我不會做到那種程度。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};